        ///  # Safety
        ///  `v` must be null or a live handle.
        /// </summary>
        [DllImport(__DllName, EntryPoint = "mangle_val_compound_get", CallingConvention = CallingConvention.Cdecl, ExactSpelling = true)]
        internal static extern Value* mangle_val_compound_get(Value* v, nuint index);

        /// <summary>
        ///  Borrowed handles to the key and value at a given pair index in a
