        ///  # Safety
        ///  `v`, `key_out`, and `val_out` must be non-null and live.
        /// </summary>
        [DllImport(__DllName, EntryPoint = "mangle_val_compound_kv", CallingConvention = CallingConvention.Cdecl, ExactSpelling = true)]
        internal static extern int mangle_val_compound_kv(Value* v, nuint pair_index, Value** key_out, Value** val_out);

        /// <summary>
        ///  Construct a new value builder. Returns null on allocation failure
        ///  (which is currently unreachable, but the C ABI consumer should still
        ///  check). Release with [`mangle_val_builder_free`].
        ///
        ///  # Safety
        ///  Safe to call from any context; the `unsafe` marker is for ABI
        ///  consistency with the other entry points in this crate.
        /// </summary>
        [DllImport(__DllName, EntryPoint = "mangle_val_builder_new", CallingConvention = CallingConvention.Cdecl, ExactSpelling = true)]
        internal static extern MangleValBuilder* mangle_val_builder_new();

        /// <summary>
