        ///  # Safety
        ///  `b` must be a live builder.
        /// </summary>
        [DllImport(__DllName, EntryPoint = "mangle_val_build_null", CallingConvention = CallingConvention.Cdecl, ExactSpelling = true)]
        internal static extern Value* mangle_val_build_null(MangleValBuilder* b);

