        [DllImport(__DllName, EntryPoint = "mangle_val_build_i64", CallingConvention = CallingConvention.Cdecl, ExactSpelling = true)]
        internal static extern Value* mangle_val_build_i64(MangleValBuilder* b, long n);

        /// <summary>
