        ///  # Safety
        ///  `b` must be a live builder.
        /// </summary>
        [DllImport(__DllName, EntryPoint = "mangle_val_build_f64", CallingConvention = CallingConvention.Cdecl, ExactSpelling = true)]
        internal static extern Value* mangle_val_build_f64(MangleValBuilder* b, double f);

        /// <summary>
