        ///
        ///  # Safety
        ///  `b` must be a live builder.
        /// </summary>
        [DllImport(__DllName, EntryPoint = "mangle_val_build_time_ns", CallingConvention = CallingConvention.Cdecl, ExactSpelling = true)]
