        ///  # Safety
        ///  `b` must be a live builder.
        /// </summary>
        [DllImport(__DllName, EntryPoint = "mangle_val_build_duration_ns", CallingConvention = CallingConvention.Cdecl, ExactSpelling = true)]
        internal static extern Value* mangle_val_build_duration_ns(MangleValBuilder* b, long nanos);

        /// <summary>
        ///  Build a `String` value from a UTF-8 byte slice. Returns null and
