        ///  # Safety
        ///  `b` must be live. `s` must point to `len` readable bytes (or be null
        ///  with `len == 0`).
        /// </summary>
        [DllImport(__DllName, EntryPoint = "mangle_val_build_string", CallingConvention = CallingConvention.Cdecl, ExactSpelling = true)]
