        /// </summary>
        [DllImport(__DllName, EntryPoint = "mangle_val_build_name", CallingConvention = CallingConvention.Cdecl, ExactSpelling = true)]
        internal static extern Value* mangle_val_build_name(MangleValBuilder* b, byte* s, nuint len);

        /// <summary>
        ///  Build a compound value (`List`, `Pair`, `Map`, or `Struct`) by
        ///  cloning the given element handles into a new `Value::Compound`.
        ///
        ///  `subkind` selects the compound kind via the `MANGLE_COMPOUND_*`
